import React, {useState} from "react";
import './Welcome.css';
import axios from 'axios'
import { useNavigate } from "react-router-dom";
import { useAuth } from "./auth";

function Welcome () {


    const [userName, setUserName] = useState('');
    const [passWord, setPassWord] = useState('');
    const [isLoginSuccessful, setIsLoginSuccessful] = useState(false);
    const [invalidCreds, setInvalidCreds] = useState(false);
    const [response, setResponse] = useState('');
    const navigate = useNavigate();
    const handleUsernameChange = (e) => {
        e.preventDefault();
        const value = e.target.value;
        setUserName(value);
    }
    const handlePasswordChange = (e) => {
        e.preventDefault();
        const value = e.target.value;
        setPassWord(value);
    }
    const auth = useAuth();
    const Login = (e) => {
        e.preventDefault();
        auth.login(userName)
        if (userName === 'Admin' && passWord === '1234') {
            setIsLoginSuccessful(true);
            setInvalidCreds(false);
            Credentials(isLoginSuccessful);
            navigate('Welcome', {replace: true })
            axios.get(`http://localhost:8080/users/Admin/items`).then(response => console.log(response.data))
            .catch(error => setIsLoginSuccessful(false)); // Fix this for an error pafe backend and not condtionals, 404 or 500 error via axious.
        }
        else {
            setInvalidCreds(true);
            InvalidCredentials(invalidCreds);
            setIsLoginSuccessful(false);
            Credentials(isLoginSuccessful);
        }
    }
    const Credentials = () => {
        if (isLoginSuccessful)  
        {  
            return response;
        }
    }
    const InvalidCredentials = () => {
        if (invalidCreds)  
        {  
            return (
                        <div className="error-message">Invalid Credential!</div>
                    )
        }
    }
    return  (
        <section class="vh-100">
  <div class="container py-5 h-100">
    <div class="row d-flex align-items-center justify-content-center h-100">
      <div class="col-md-8 col-lg-7 col-xl-6">
        <img src="https://mdbcdn.b-cdn.net/img/Photos/new-templates/bootstrap-login-form/draw2.svg">
          class="img-fluid" alt="Phone image"</img>
      </div>
      <div class="col-md-7 col-lg-5 col-xl-5 offset-xl-1">
        <form>
          <div class="form-outline mb-4">
            <input type="email" id="form1Example13" class="form-control form-control-lg" />
            <label class="form-label" for="form1Example13">Email address</label>
          </div>

          <div class="form-outline mb-4">
            <input type="password" id="form1Example23" class="form-control form-control-lg" />
            <label class="form-label" for="form1Example23">Password</label>
          </div>

          <div class="d-flex justify-content-around align-items-center mb-4">
            <div class="form-check">
              <input class="form-check-input" type="checkbox" value="" id="form1Example3" checked />
              <label class="form-check-label" for="form1Example3"> Remember me </label>
            </div>
            <a href="#!">Forgot password?</a>
          </div>

          <button type="submit" class="btn btn-primary btn-lg btn-block">Sign in</button>

          <div class="divider d-flex align-items-center my-4">
            <p class="text-center fw-bold mx-3 mb-0 text-muted">OR</p>
          </div>

          <a class="btn btn-primary btn-lg btn-block" style="background-color: #3b5998" href="#!"
            role="button">
            <i class="fab fa-facebook-f me-2"></i>Continue with Facebook
          </a>
          <a class="btn btn-primary btn-lg btn-block" style="background-color: #55acee" href="#!"
            role="button">
            <i class="fab fa-twitter me-2"></i>Continue with Twitter</a>

        </form>
      </div>
    </div>
  </div>
</section>
    )
    }

export default Welcome;
